-- ============================================
-- 乔治·索罗斯名言
-- ============================================

INSERT OR IGNORE INTO quotes (id, content_cn, content_en, master_id, source, source_year, is_featured) VALUES
('eq-s001', '我有幸在正确的时候出现在正确的地方，这让我赚了很多钱。', 'I was lucky to be in the right place at the right time, which allowed me to make a lot of money.', 'm-soros', '索罗斯谈索罗斯', 1995, 0),
('eq-s002', '当你对一笔交易有疑虑时，那往往是最危险的交易。', 'When you have doubts about a trade, that is often the most dangerous trade.', 'm-soros', '金融炼金术', 1987, 0),
('eq-s003', '我不认为自己是一个投资者，我是一个试图发现市场错误定价的人。', 'I do not think of myself as an investor; I am someone trying to discover market mispricing.', 'm-soros', '索罗斯谈索罗斯', 1995, 0),
('eq-s004', '在交易中，最重要的是知道什么时候退出。', 'In trading, the most important thing is knowing when to exit.', 'm-soros', '金融炼金术', 1987, 0),
('eq-s005', '我的成功来自于对错误的快速承认和纠正。', 'My success comes from quickly acknowledging and correcting mistakes.', 'm-soros', '索罗斯谈索罗斯', 1995, 0),
('eq-s006', '市场总是错误的，因为参与者的认知是有偏见的。', 'Markets are always wrong because participants perceptions are biased.', 'm-soros', '金融炼金术', 1987, 0),
('eq-s007', '趋势是你的朋友，除非趋势反转。', 'The trend is your friend until the trend reverses.', 'm-soros', '金融炼金术', 1987, 0),
('eq-s008', '我寻找的是极端的失衡，而不是小幅的偏差。', 'I look for extreme disequilibrium, not small deviations.', 'm-soros', '金融炼金术', 1987, 0),
('eq-s009', '最好的交易往往是那些让你感到不舒服的交易。', 'The best trades are often those that make you feel uncomfortable.', 'm-soros', '索罗斯谈索罗斯', 1995, 0),
('eq-s010', '当你发现趋势正在形成时，不要过早地逆势而行。', 'When you find a trend forming, do not be too early to go against it.', 'm-soros', '金融炼金术', 1987, 0),
('eq-s011', '最重要的是不要赔钱，其次是记住第一条。', 'The most important thing is not to lose money; remember the first rule.', 'm-soros', '索罗斯谈索罗斯', 1995, 0),
('eq-s012', '我从不固守任何一笔交易，如果市场证明我错了，我会立即退出。', 'I never cling to any trade; if the market proves me wrong, I exit immediately.', 'm-soros', '金融炼金术', 1987, 0),
('eq-s013', '如果你交易得太多，你肯定会犯错。', 'If you trade too much, you are sure to make mistakes.', 'm-soros', '索罗斯谈索罗斯', 1995, 0),
('eq-s014', '在金融市场上，最重要的不是预测，而是适应。', 'In financial markets, the most important thing is not prediction, but adaptation.', 'm-soros', '金融炼金术', 1987, 0),
('eq-s015', '我的投资哲学基于一个简单的观点：人们对现实的看法总是有偏差的。', 'My investment philosophy is based on a simple idea: peoples perceptions of reality are always biased.', 'm-soros', '索罗斯谈索罗斯', 1995, 0),
('eq-s016', '如果你发现自己处于一个无法退出的位置，那就是你投入太多的信号。', 'If you find yourself in a position you cannot exit, that is a signal you are too invested.', 'm-soros', '金融炼金术', 1987, 0),
('eq-s017', '成功的人不是没有失败，而是能够从失败中快速恢复。', 'Successful people are not those without failures, but those who recover quickly from failures.', 'm-soros', '索罗斯谈索罗斯', 1995, 0),
('eq-s018', '金融市场是非理性的，这种非理性是可以预测的。', 'Financial markets are irrational, and this irrationality is predictable.', 'm-soros', '金融炼金术', 1987, 0),
('eq-s019', '不要试图战胜市场，要学会利用市场的错误。', 'Do not try to beat the market; learn to exploit market mistakes.', 'm-soros', '索罗斯谈索罗斯', 1995, 0),
('eq-s020', '趋势反转的信号是当所有人都站在同一边时。', 'The signal of a trend reversal is when everyone is on the same side.', 'm-soros', '金融炼金术', 1987, 0),
('eq-s021', '我在市场上生存的秘诀是知道自己什么时候是错的。', 'The secret to my survival in the market is knowing when I am wrong.', 'm-soros', '索罗斯谈索罗斯', 1995, 0),
('eq-s022', '金融市场的历史是一部谎言和假象的历史。', 'The history of financial markets is a history of lies and falsehoods.', 'm-soros', '金融炼金术', 1987, 0),
('eq-s023', '在市场上，最危险的事情是自满。', 'In the market, the most dangerous thing is complacency.', 'm-soros', '索罗斯谈索罗斯', 1995, 0),
('eq-s024', '我不关心我对市场的看法，我只关心市场对事件的反应。', 'I do not care about my view of the market; I only care about how the market reacts to events.', 'm-soros', '金融炼金术', 1987, 0),
('eq-s025', '成功的交易需要耐心、勇气和资金管理。', 'Successful trading requires patience, courage, and money management.', 'm-soros', '索罗斯谈索罗斯', 1995, 0),
('eq-s026', '如果你发现自己在重复同样的错误，那是你需要改变的时候了。', 'If you find yourself repeating the same mistakes, it is time for you to change.', 'm-soros', '金融炼金术', 1987, 0),
('eq-s027', '在市场上，钱是从恐慌者手中转移到自信者手中的。', 'In the market, money transfers from panickers to the confident.', 'm-soros', '索罗斯谈索罗斯', 1995, 0),
('eq-s028', '我不寻找确定性，我寻找机会。', 'I do not look for certainty; I look for opportunities.', 'm-soros', '金融炼金术', 1987, 0),
('eq-s029', '趋势开始时很温和，结束时很剧烈。', 'Trends start gentle and end violently.', 'm-soros', '索罗斯谈索罗斯', 1995, 0),
('eq-s030', '最重要的事情是知道什么时候止损。', 'The most important thing is knowing when to stop losses.', 'm-soros', '金融炼金术', 1987, 0),
('eq-s031', '金融市场是一个巨大的实验室，测试你的理论。', 'Financial markets are a huge laboratory testing your theories.', 'm-soros', '索罗斯谈索罗斯', 1995, 0),
('eq-s032', '我寻找的是那些被严重错误定价的资产。', 'I look for assets that are severely mispriced.', 'm-soros', '金融炼金术', 1987, 0),
('eq-s033', '不要和市场作对，要学会顺势而为。', 'Do not fight the market; learn to go with the flow.', 'm-soros', '索罗斯谈索罗斯', 1995, 0),
('eq-s034', '成功的关键是风险管理，而不是预测。', 'The key to success is risk management, not prediction.', 'm-soros', '金融炼金术', 1987, 0),
('eq-s035', '当我交易时，我总是假设我是错的。', 'When I trade, I always assume I am wrong.', 'm-soros', '索罗斯谈索罗斯', 1995, 0),
('eq-s036', '市场的极端行为往往孕育着反转的机会。', 'Extreme market behavior often breeds opportunities for reversal.', 'm-soros', '金融炼金术', 1987, 0),
('eq-s037', '我不在乎别人怎么看我，我只在乎我怎么看市场。', 'I do not care what others think of me; I only care about how I see the market.', 'm-soros', '索罗斯谈索罗斯', 1995, 0),
('eq-s038', '交易的艺术在于知道什么时候加仓，什么时候减仓。', 'The art of trading is knowing when to add to positions and when to reduce them.', 'm-soros', '金融炼金术', 1987, 0),
('eq-s039', '如果你发现自己在市场上追涨杀跌，那是你亏钱的捷径。', 'If you find yourself chasing rises and cutting losses in the market, that is a shortcut to losing money.', 'm-soros', '索罗斯谈索罗斯', 1995, 0),
('eq-s040', '市场永远不会直线上升或下降，它总是曲折前进。', 'The market never rises or falls in a straight line; it always moves zigzag.', 'm-soros', '金融炼金术', 1987, 0),
('eq-s041', '最重要的是保持灵活性，随时准备改变观点。', 'The most important thing is to stay flexible and be ready to change your views.', 'm-soros', '索罗斯谈索罗斯', 1995, 0),
('eq-s042', '我从不根据预感做交易，我根据市场信号做交易。', 'I never trade on hunches; I trade on market signals.', 'm-soros', '金融炼金术', 1987, 0),
('eq-s043', '在市场上，最大的错误是坚持错误。', 'In the market, the biggest mistake is persisting in errors.', 'm-soros', '索罗斯谈索罗斯', 1995, 0),
('eq-s044', '市场的记忆是短暂的，这创造了重复的机会。', 'The markets memory is short, which creates repeated opportunities.', 'm-soros', '金融炼金术', 1987, 0),
('eq-s045', '成功的交易者不是那些预测最准确的人，而是那些风险管理最好的人。', 'Successful traders are not those who predict most accurately, but those who manage risk best.', 'm-soros', '索罗斯谈索罗斯', 1995, 0),
('eq-s046', '金融市场是一个复杂的自适应系统。', 'Financial markets are complex adaptive systems.', 'm-soros', '金融炼金术', 1987, 0),
('eq-s047', '我寻找的是那些有自我强化趋势的市场。', 'I look for markets that have self-reinforcing trends.', 'm-soros', '索罗斯谈索罗斯', 1995, 0),
('eq-s048', '在市场上，最重要的不是你对了多少次，而是你对的时候赚了多少。', 'In the market, the most important thing is not how many times you are right, but how much you make when you are right.', 'm-soros', '金融炼金术', 1987, 0),
('eq-s049', '市场先生的情绪可以在短期内推动价格远离价值。', 'Mr. Markets emotions can push prices far from value in the short term.', 'm-soros', '索罗斯谈索罗斯', 1995, 0),
('eq-s050', '成功的关键是能够在正确的时候下大注。', 'The key to success is being able to place big bets when you are right.', 'm-soros', '金融炼金术', 1987, 0);

