-- ============================================
-- 瑞·达利欧名言
-- ============================================

INSERT OR IGNORE INTO quotes (id, content_cn, content_en, master_id, source, source_year, is_featured) VALUES
('eq-d001', '我相信任何事情都有循环，成功的关键是顺应这些循环。', 'I believe everything has cycles, and the key to success is to go with these cycles.', 'm-dalio', '原则', 2017, 0),
('eq-d002', '大多数人在面对痛苦时会回避，而不是拥抱它并从中学习。', 'Most people avoid pain rather than embrace it and learn from it.', 'm-dalio', '原则', 2017, 0),
('eq-d003', '真相是成功最坚实的基础。', 'Truth is the most solid foundation for success.', 'm-dalio', '原则', 2017, 0),
('eq-d004', '最好的决策来自于把最好的思考与最好的决策过程结合起来。', 'The best decisions come from combining the best thinking with the best decision-making process.', 'm-dalio', '原则', 2017, 0),
('eq-d005', '我相信极度求真，极度透明。', 'I believe in being radically truthful and radically transparent.', 'm-dalio', '原则', 2017, 0),
('eq-d006', '失败是学习的最好机会，不要害怕失败。', 'Failure is the best opportunity to learn; do not be afraid of failure.', 'm-dalio', '原则', 2017, 0),
('eq-d007', '理解历史和经济周期可以帮助你做出更好的投资决策。', 'Understanding history and economic cycles can help you make better investment decisions.', 'm-dalio', '原则', 2017, 0),
('eq-d008', '大多数人的最大问题是没有开放的头脑。', 'Most peoples biggest problem is not having an open mind.', 'm-dalio', '原则', 2017, 0),
('eq-d009', '你想要什么，你就能得到什么，只要你愿意为此付出代价。', 'You can have whatever you want as long as you are willing to pay the price.', 'm-dalio', '原则', 2017, 0),
('eq-d010', '理解债务周期是理解经济的关键。', 'Understanding the debt cycle is the key to understanding the economy.', 'm-dalio', '原则', 2017, 0),
('eq-d011', '在市场上生存的关键是理解风险，而不是试图避免风险。', 'The key to survival in the market is understanding risk, not trying to avoid it.', 'm-dalio', '原则', 2017, 0),
('eq-d012', '我相信多角度思考，而不只是单一角度。', 'I believe in multi-perspective thinking, not just a single perspective.', 'm-dalio', '原则', 2017, 0),
('eq-d013', '把错误当作学习的机会，而不是失败的标志。', 'Treat mistakes as learning opportunities, not as signs of failure.', 'm-dalio', '原则', 2017, 0),
('eq-d014', '我建立桥水不是为了赚钱，而是为了理解经济运作的原理。', 'I built Bridgewater not to make money, but to understand how the economy works.', 'm-dalio', '原则', 2017, 0),
('eq-d015', '最成功的决策来自于把可信度加权与独立思考结合起来。', 'The most successful decisions come from combining believability weighting with independent thinking.', 'm-dalio', '原则', 2017, 0),
('eq-d016', '理解因果关系是预测未来的关键。', 'Understanding cause-and-effect relationships is the key to predicting the future.', 'm-dalio', '原则', 2017, 0),
('eq-d017', '我学到的一个最重要的教训是：差异化思维是成功的关键。', 'One of the most important lessons I learned is that differentiated thinking is the key to success.', 'm-dalio', '原则', 2017, 0),
('eq-d018', '不要把未来简单地从过去推断，因为情况会变化。', 'Do not extrapolate the future simply from the past because situations change.', 'm-dalio', '原则', 2017, 0),
('eq-d019', '成功的生活需要平衡，接受现实并努力改变。', 'A successful life requires balance, accepting reality while striving to change it.', 'm-dalio', '原则', 2017, 0),
('eq-d020', '理解他人的视角可以帮助你做出更好的决策。', 'Understanding others perspectives can help you make better decisions.', 'm-dalio', '原则', 2017, 0),
('eq-d021', '投资的核心是理解风险与回报的关系。', 'The core of investing is understanding the relationship between risk and return.', 'm-dalio', '原则', 2017, 0),
('eq-d022', '我相信通过原则生活，而不是通过记忆生活。', 'I believe in living by principles rather than by memory.', 'm-dalio', '原则', 2017, 0),
('eq-d023', '大多数痛苦来自于你期望的和你得到的之间的差距。', 'Most pain comes from the gap between what you expect and what you get.', 'm-dalio', '原则', 2017, 0),
('eq-d024', '理解自己的弱点是改进的第一步。', 'Understanding your own weaknesses is the first step to improvement.', 'm-dalio', '原则', 2017, 0),
('eq-d025', '好的想法需要经过压力测试才能成为好决策。', 'Good ideas need to be stress-tested to become good decisions.', 'm-dalio', '原则', 2017, 0),
('eq-d026', '我相信系统性思考，而不只是线性思考。', 'I believe in systemic thinking, not just linear thinking.', 'm-dalio', '原则', 2017, 0),
('eq-d027', '在投资中，最重要的事情是理解你在赌什么。', 'In investing, the most important thing is understanding what you are betting on.', 'm-dalio', '原则', 2017, 0),
('eq-d028', '大多数人在决策时会受到情绪的影响。', 'Most people are influenced by emotions when making decisions.', 'm-dalio', '原则', 2017, 0),
('eq-d029', '理解历史周期可以帮助你避免重蹈覆辙。', 'Understanding historical cycles can help you avoid repeating mistakes.', 'm-dalio', '原则', 2017, 0),
('eq-d030', '我相信想法的精英制度，让最好的想法胜出。', 'I believe in an idea meritocracy, letting the best ideas win.', 'm-dalio', '原则', 2017, 0),
('eq-d031', '痛苦加反思等于进步，这是我在生活中学到的最重要的公式。', 'Pain plus reflection equals progress; this is the most important formula I have learned in life.', 'm-dalio', '原则', 2017, 0),
('eq-d032', '不要把希望和现实混为一谈。', 'Do not confuse hope with reality.', 'm-dalio', '原则', 2017, 0),
('eq-d033', '成功的关键不是避免错误，而是从错误中快速学习。', 'The key to success is not avoiding mistakes, but learning quickly from them.', 'm-dalio', '原则', 2017, 0),
('eq-d034', '我相信多元化和分散投资的重要性。', 'I believe in the importance of diversification and spread investing.', 'm-dalio', '原则', 2017, 0),
('eq-d035', '理解不同资产类别的相关性是风险管理的基础。', 'Understanding correlations between different asset classes is the foundation of risk management.', 'm-dalio', '原则', 2017, 0),
('eq-d036', '在市场上最重要的不是你的看法对不对，而是你的看法对的时候你赚了多少。', 'In the market, the most important thing is not whether your view is right, but how much you make when you are right.', 'm-dalio', '原则', 2017, 0),
('eq-d037', '我相信通过数据和逻辑做决策，而不是通过情绪。', 'I believe in making decisions through data and logic, not through emotions.', 'm-dalio', '原则', 2017, 0),
('eq-d038', '理解经济的运作原理是投资成功的基础。', 'Understanding how the economy works is the foundation of investment success.', 'm-dalio', '原则', 2017, 0),
('eq-d039', '我相信每个人都有自己的优点和缺点，关键是发挥优点，管理缺点。', 'I believe everyone has their own strengths and weaknesses; the key is to leverage strengths and manage weaknesses.', 'm-dalio', '原则', 2017, 0),
('eq-d040', '在处理问题时，要分清主要矛盾和次要矛盾。', 'When handling problems, distinguish between primary and secondary contradictions.', 'm-dalio', '原则', 2017, 0),
('eq-d041', '我相信极度开放，同时极度有原则。', 'I believe in being radically open-minded while being radically principled.', 'm-dalio', '原则', 2017, 0),
('eq-d042', '理解你周围人的优点和缺点可以帮助你更好地与他们合作。', 'Understanding the strengths and weaknesses of people around you can help you cooperate better with them.', 'm-dalio', '原则', 2017, 0),
('eq-d043', '成功的决策需要好的输入和好的处理过程。', 'Successful decisions require good inputs and good processing.', 'm-dalio', '原则', 2017, 0),
('eq-d044', '我相信在决策时要保持冷静，不受情绪影响。', 'I believe in staying calm when making decisions and not being influenced by emotions.', 'm-dalio', '原则', 2017, 0),
('eq-d045', '理解政治和经济之间的互动是预测未来的关键。', 'Understanding the interaction between politics and economics is the key to predicting the future.', 'm-dalio', '原则', 2017, 0),
('eq-d046', '我相信通过写下来的原则来指导决策。', 'I believe in guiding decisions through written principles.', 'm-dalio', '原则', 2017, 0),
('eq-d047', '理解债务和货币的运作原理是理解经济危机的关键。', 'Understanding how debt and money work is the key to understanding economic crises.', 'm-dalio', '原则', 2017, 0),
('eq-d048', '我相信建立系统来做出好的决策，而不是依赖直觉。', 'I believe in building systems to make good decisions rather than relying on intuition.', 'm-dalio', '原则', 2017, 0),
('eq-d049', '理解不同类型风险的特性是资产配置的基础。', 'Understanding the characteristics of different types of risk is the foundation of asset allocation.', 'm-dalio', '原则', 2017, 0),
('eq-d050', '我相信持续学习是成功的关键。', 'I believe continuous learning is the key to success.', 'm-dalio', '原则', 2017, 0);

