-- ============================================
-- 霍华德·马克斯名言
-- ============================================

INSERT OR IGNORE INTO quotes (id, content_cn, content_en, master_id, source, source_year, is_featured) VALUES
('eq-h001', '在市场过热时保持怀疑，在市场恐慌时保持勇气。', 'Remain skeptical when the market is overheating, and courageous when the market panics.', 'm-marks', '投资最重要的事', 2011, 0),
('eq-h002', '第二层思维是区分普通投资者和优秀投资者的关键。', 'Second-level thinking is the key to distinguishing ordinary investors from excellent ones.', 'm-marks', '投资最重要的事', 2011, 0),
('eq-h003', '高风险只能带来高回报的说法是错误的。', 'The statement that high risk can only lead to high returns is wrong.', 'm-marks', '投资最重要的事', 2011, 0),
('eq-h004', '市场价格已经反映了大多数人的共识。', 'Market prices already reflect the consensus of most people.', 'm-marks', '投资最重要的事', 2011, 0),
('eq-h005', '投资的成功取决于你做得比市场更好，而不只是与市场一致。', 'Investment success depends on you doing better than the market, not just matching it.', 'm-marks', '投资最重要的事', 2011, 0),
('eq-h006', '最危险的投资是那些看起来最安全的投资。', 'The most dangerous investments are those that look safest.', 'm-marks', '投资最重要的事', 2011, 0),
('eq-h007', '理解风险是投资成功的关键，而不是追求回报。', 'Understanding risk is the key to investment success, not pursuing returns.', 'm-marks', '投资最重要的事', 2011, 0),
('eq-h008', '市场的周期性是不可避免的，关键是知道我们在周期中的位置。', 'Market cyclicality is inevitable; the key is knowing where we are in the cycle.', 'm-marks', '投资最重要的事', 2011, 0),
('eq-h009', '好的投资是那些在买入时就能够提供安全边际的投资。', 'Good investments are those that provide a margin of safety when bought.', 'm-marks', '投资最重要的事', 2011, 0),
('eq-h010', '在投资中，过度自信是最大的敌人。', 'In investing, overconfidence is the biggest enemy.', 'm-marks', '投资最重要的事', 2011, 0),
('eq-h011', '耐心等待合适的价格是投资成功的关键。', 'Patiently waiting for the right price is the key to investment success.', 'm-marks', '投资最重要的事', 2011, 0),
('eq-h012', '分散投资可以降低风险，但不能消除风险。', 'Diversification can reduce risk, but cannot eliminate it.', 'm-marks', '投资最重要的事', 2011, 0),
('eq-h013', '在投资中，最重要的是不要亏钱。', 'In investing, the most important thing is not to lose money.', 'm-marks', '投资最重要的事', 2011, 0),
('eq-h014', '逆向投资意味着在别人卖出时买入，在别人买入时卖出。', 'Contrarian investing means buying when others sell and selling when others buy.', 'm-marks', '投资最重要的事', 2011, 0),
('eq-h015', '理解估值是投资的基础，而不是追逐热门。', 'Understanding valuation is the foundation of investing, not chasing popular stocks.', 'm-marks', '投资最重要的事', 2011, 0),
('eq-h016', '投资于不确定性是最大的错误。', 'Investing in uncertainty is the biggest mistake.', 'm-marks', '投资最重要的事', 2011, 0),
('eq-h017', '在市场顶部时保持谦虚，在市场底部时保持贪婪。', 'Stay humble at market tops and greedy at market bottoms.', 'm-marks', '投资最重要的事', 2011, 0),
('eq-h018', '好的投资需要耐心和纪律。', 'Good investing requires patience and discipline.', 'm-marks', '投资最重要的事', 2011, 0),
('eq-h019', '风险是投资中最重要的考虑因素。', 'Risk is the most important consideration in investing.', 'm-marks', '投资最重要的事', 2011, 0),
('eq-h020', '理解周期可以帮助你避免在顶部买入，在底部卖出。', 'Understanding cycles can help you avoid buying at the top and selling at the bottom.', 'm-marks', '周期', 2018, 0),
('eq-h021', '在投资中，情绪是最大的敌人。', 'In investing, emotions are the biggest enemy.', 'm-marks', '投资最重要的事', 2011, 0),
('eq-h022', '成功的投资需要你能够在别人恐惧时保持冷静。', 'Successful investing requires you to stay calm when others are fearful.', 'm-marks', '投资最重要的事', 2011, 0),
('eq-h023', '投资回报与所承担的风险之间没有简单的线性关系。', 'There is no simple linear relationship between investment returns and risk assumed.', 'm-marks', '投资最重要的事', 2011, 0),
('eq-h024', '好的投资者在别人不想要的时候买入。', 'Good investors buy when others do not want it.', 'm-marks', '投资最重要的事', 2011, 0),
('eq-h025', '理解市场的钟摆特性可以帮助你做出更好的投资决策。', 'Understanding the pendulum nature of markets can help you make better investment decisions.', 'm-marks', '投资最重要的事', 2011, 0),
('eq-h026', '在投资中，最重要的不是你的看法对不对，而是你知道你可能是错的。', 'In investing, the most important thing is not whether your view is right, but knowing you might be wrong.', 'm-marks', '投资最重要的事', 2011, 0),
('eq-h027', '好的投资者会在市场过度乐观时变得谨慎。', 'Good investors become cautious when the market is overly optimistic.', 'm-marks', '投资最重要的事', 2011, 0),
('eq-h028', '理解自己不知道什么是投资智慧的开始。', 'Understanding what you do not know is the beginning of investment wisdom.', 'm-marks', '投资最重要的事', 2011, 0),
('eq-h029', '在投资中，避免错误比追求正确更重要。', 'In investing, avoiding mistakes is more important than pursuing correctness.', 'm-marks', '投资最重要的事', 2011, 0),
('eq-h030', '好的投资是那些你可以在最坏情况下也能持有的投资。', 'Good investments are those you can hold even in the worst case.', 'm-marks', '投资最重要的事', 2011, 0),
('eq-h031', '在投资中，价格是最重要的变量。', 'In investing, price is the most important variable.', 'm-marks', '投资最重要的事', 2011, 0),
('eq-h032', '成功的投资者是那些能够独立思考的人。', 'Successful investors are those who can think independently.', 'm-marks', '投资最重要的事', 2011, 0),
('eq-h033', '理解心理因素在投资中的作用是至关重要的。', 'Understanding the role of psychological factors in investing is crucial.', 'm-marks', '投资最重要的事', 2011, 0),
('eq-h034', '在市场繁荣时要想到风险，在市场萧条时要想到机会。', 'Think about risk when the market is booming, and think about opportunities when the market is depressed.', 'm-marks', '周期', 2018, 0),
('eq-h035', '好的投资者会在投资前做充分的尽职调查。', 'Good investors do thorough due diligence before investing.', 'm-marks', '投资最重要的事', 2011, 0),
('eq-h036', '理解价值的来源是投资成功的关键。', 'Understanding the sources of value is the key to investment success.', 'm-marks', '投资最重要的事', 2011, 0),
('eq-h037', '在投资中，便宜是硬道理。', 'In investing, cheapness is hard truth.', 'm-marks', '投资最重要的事', 2011, 0),
('eq-h038', '成功的投资不是关于预测未来，而是关于为未来做准备。', 'Successful investing is not about predicting the future, but about being prepared for it.', 'm-marks', '投资最重要的事', 2011, 0),
('eq-h039', '在投资中，最重要的品质是耐心和理性。', 'In investing, the most important qualities are patience and rationality.', 'm-marks', '投资最重要的事', 2011, 0),
('eq-h040', '理解市场的历史可以帮助你避免犯同样的错误。', 'Understanding market history can help you avoid making the same mistakes.', 'm-marks', '周期', 2018, 0),
('eq-h041', '好的投资是那些即使在不利情况下也能保护你本金的的投资。', 'Good investments are those that protect your principal even in adverse conditions.', 'm-marks', '投资最重要的事', 2011, 0),
('eq-h042', '在投资中，你需要知道什么时候应该坚持，什么时候应该放弃。', 'In investing, you need to know when to persist and when to give up.', 'm-marks', '投资最重要的事', 2011, 0),
('eq-h043', '理解风险溢价是理解投资回报的基础。', 'Understanding risk premium is the foundation of understanding investment returns.', 'm-marks', '投资最重要的事', 2011, 0),
('eq-h044', '在市场顶部时，风险最大，回报最小。', 'At market tops, risk is highest and returns are smallest.', 'm-marks', '周期', 2018, 0),
('eq-h045', '好的投资者会时刻关注风险，而不是只关注回报。', 'Good investors always focus on risk, not just on returns.', 'm-marks', '投资最重要的事', 2011, 0),
('eq-h046', '在投资中，过度反应是人性的一部分。', 'In investing, overreaction is part of human nature.', 'm-marks', '投资最重要的事', 2011, 0),
('eq-h047', '理解流动性在投资中的作用是重要的。', 'Understanding the role of liquidity in investing is important.', 'm-marks', '投资最重要的事', 2011, 0),
('eq-h048', '成功的投资者知道什么时候应该逆向而行。', 'Successful investors know when they should go against the grain.', 'm-marks', '投资最重要的事', 2011, 0),
('eq-h049', '在投资中，便宜和优质同样重要。', 'In investing, cheapness and quality are equally important.', 'm-marks', '投资最重要的事', 2011, 0),
('eq-h050', '理解自己为什么能够赚钱是持续成功的关键。', 'Understanding why you make money is the key to continued success.', 'm-marks', '投资最重要的事', 2011, 0);

